class Solution {
public:
    int maxScore(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        int score = 0;
        for (int i = 0; i < nums.size() / 2; i++) {
            score += (i + 1) * __gcd(nums[i], nums[nums.size() - i - 1]);
        }
        return score;
    }
};
